12	func AnalyzeGitRange(ctx context.Context, repo, base, head string, paths []string) (Result, error) {
13		changed, err := gitutil.ChangedFiles(ctx, repo, base, head, paths)
14		if err != nil {
15			return Result{}, err
16		}
17		parser := TreeSitterParser{}
18		result := Result{Base: base, Head: head}
19		for _, file := range changed {
20			path := file.Path
21			oldPath := file.OldPath
22			if oldPath == "" {
23				oldPath = path
24			}
25			if !Supported(path) && !Supported(oldPath) {
26				continue
27			}
28	
29			var before, after string
30			var beforeOK, afterOK bool
31			if file.Status != "A" {
32				before, beforeOK, err = gitutil.ShowFile(ctx, repo, base, oldPath)
33				if err != nil {
34					return Result{}, err
35				}
36			}
37			if file.Status != "D" {
38				after, afterOK, err = gitutil.ShowFile(ctx, repo, head, path)
39				if err != nil {
40					return Result{}, err
41				}
42			}
43	
44			beforeEntities, language := parser.Parse(oldPath, before)
45			afterEntities, afterLanguage := parser.Parse(path, after)
46			if language == "" {
47				language = afterLanguage
48			}
49			if !beforeOK {
50				beforeEntities = nil
51			}
52			if !afterOK {
53				afterEntities = nil
54			}
55	
56			changes := Compare(beforeEntities, afterEntities)
57			if len(changes) == 0 {
58				continue
59			}
60			result.Files = append(result.Files, FileChange{
61				Path:     path,
62				OldPath:  file.OldPath,
63				Status:   file.Status,
64				Language: language,
65				Changes:  changes,
66			})
67		}
68		if err := addDependentCounts(ctx, repo, head, &result); err != nil {
69			return Result{}, err
70		}
71		return result, nil
72	}
73	
74	func AnalyzeCheckpoint(ctx context.Context, repo, checkpointID string) (Result, error) {
75		head, err := gitutil.FindCommitWithCheckpoint(ctx, repo, checkpointID)
76		if err != nil {
77			return Result{}, err
78		}
79		base, err := gitutil.FirstParent(ctx, repo, head)
80		if err != nil {
81			return Result{}, err
82		}
83		result, err := AnalyzeGitRange(ctx, repo, base, head, nil)
84		if err != nil {
85			return Result{}, err
86		}
87		result.Checkpoint = checkpointID
88		return result, nil
89	}
90	
91	func Compare(before, after []Entity) []EntityChange {
92		beforeByKey := map[string]Entity{}
93		afterByKey := map[string]Entity{}
94		for _, entity := range before {
95			beforeByKey[key(entity)] = entity
96		}
97		for _, entity := range after {
98			afterByKey[key(entity)] = entity
99		}
100	
101		var changes []EntityChange
102		deleted := map[string]Entity{}
103		added := map[string]Entity{}
104	
105		for key, oldEntity := range beforeByKey {
106			newEntity, ok := afterByKey[key]
107			if !ok {
108				deleted[key] = oldEntity
109				continue
110			}
111			switch {
112			case oldEntity.Signature != newEntity.Signature:
113				changes = append(changes, EntityChange{
114					Type:            "signature_changed",
115					Kind:            oldEntity.Kind,
116					Name:            oldEntity.Name,
117					OldSignature:    oldEntity.Signature,
118					NewSignature:    newEntity.Signature,
119					BeforeStartLine: oldEntity.StartLine,
120					AfterStartLine:  newEntity.StartLine,
121				})
122			case oldEntity.BodyHash != newEntity.BodyHash:
123				changes = append(changes, EntityChange{
124					Type:            "body_changed",
125					Kind:            oldEntity.Kind,
126					Name:            oldEntity.Name,
127					BeforeStartLine: oldEntity.StartLine,
128					AfterStartLine:  newEntity.StartLine,
129				})
130			}
131		}
132		for key, newEntity := range afterByKey {
133			if _, ok := beforeByKey[key]; !ok {
134				added[key] = newEntity
135			}
136		}
